let state;
try { state = JSON.parse($input.first().json.stateRaw || '{}'); } catch (e) { state = {}; }
state.history = state.history || [];
state.age = state.age ?? null;
state.hasBasic = state.hasBasic ?? null; // true/false
state.beenChina = state.beenChina ?? null; // true/false
state.city = state.city || null; // Guangzhou, Shanghai, Weihai, Harbin
state.detailGiven = state.detailGiven || false;
state.wantsAdmin = false;

const webhookBody = $('Webhook').first().json.body;
const userId = webhookBody.userId;
// pageType: 'guangzhou' | 'shanghai' | 'weihai' | 'harbin' | 'china_all' | 'combined' (LINE/รวม)
const pageType = webhookBody.pageType || 'china_all';
const rawMessage = webhookBody.message || '';
state.history.push({ role: 'user', content: rawMessage });
const text = rawMessage.toLowerCase();
const numbers = (rawMessage.match(/\d+/g) || []).map(Number);

// ----- บีบเมืองตาม pageType ถ้าเพจเฉพาะเมือง -----
const CITY_BY_PAGE = { guangzhou: 'Guangzhou', shanghai: 'Shanghai', weihai: 'Weihai', harbin: 'Harbin' };
if (CITY_BY_PAGE[pageType]) state.city = CITY_BY_PAGE[pageType];

// ----- ตรวจคำตอบรับสั้นๆ หลังให้รายละเอียดคอร์สไปแล้ว -----
const confirmWords = ['สนใจ', 'ใช่', 'ตกลง', 'โอเค', 'เอาเลย', 'อยากสมัคร', 'สมัคร'];
if (state.detailGiven && confirmWords.some(w => text.includes(w))) {
  state.wantsAdmin = true;
}

// ----- ดึงอายุ/พื้นฐานภาษา/ประวัติเคยไปจีน (deterministic) -----
if (state.age === null) {
  const a = numbers.find(n => n >= 10 && n <= 70);
  if (a !== undefined) state.age = a;
}
if (state.hasBasic === null) {
  if (/ไม่มีพื้นฐาน|ไม่มี basic|ไม่เคยเรียน/.test(text)) state.hasBasic = false;
  else if (/มีพื้นฐาน|พอได้บ้าง|hsk/.test(text)) state.hasBasic = true;
}
if (state.beenChina === null) {
  if (/ไม่เคยไปจีน|ไม่เคยไป/.test(text)) state.beenChina = false;
  else if (/เคยไปจีน|เคยไป/.test(text)) state.beenChina = true;
}

// ----- ดึงชื่อเมือง (เฉพาะกรณีเพจรวม/LINE ที่ยังไม่ถูกบีบเมือง) -----
if (!state.city) {
  if (text.includes('กว่างโจว')) state.city = 'Guangzhou';
  else if (text.includes('เซี่ยงไฮ้')) state.city = 'Shanghai';
  else if (text.includes('เวยไห่')) state.city = 'Weihai';
  else if (text.includes('ฮาร์บิน')) state.city = 'Harbin';
}

const infoComplete = state.age !== null && state.hasBasic !== null && state.beenChina !== null;
if (infoComplete && state.city) state.detailGiven = true;

return [{ json: { ...state, userId, pageType, infoComplete } }];

