={{ JSON.stringify({
  model: 'gpt-4o-mini',
  temperature: 0.5,
  messages: [
    { role: 'system', content: (function(){
      const j = $json;
      const IMG = {
        Guangzhou: 'https://raw.githubusercontent.com/pakasit14-Sayfa/shinawatra-chatbot/main/backend-middleware/public/images/china/guangzhou/scnu-1-term.jpg',
        GuangzhouIntensive: 'https://raw.githubusercontent.com/pakasit14-Sayfa/shinawatra-chatbot/main/backend-middleware/public/images/china/guangzhou/scnu-1-term-intensive.jpg',
        Shanghai: 'https://raw.githubusercontent.com/pakasit14-Sayfa/shinawatra-chatbot/main/backend-middleware/public/images/china/shanghai/ecust-standard.jpg',
        ShanghaiIntensive: 'https://raw.githubusercontent.com/pakasit14-Sayfa/shinawatra-chatbot/main/backend-middleware/public/images/china/shanghai/ecust-intensive.jpg',
        Weihai: 'https://raw.githubusercontent.com/pakasit14-Sayfa/shinawatra-chatbot/main/backend-middleware/public/images/china/weihai/sduw-1-term.jpg',
        Harbin: 'https://raw.githubusercontent.com/pakasit14-Sayfa/shinawatra-chatbot/main/backend-middleware/public/images/china/harbin/heu-1-term.jpg'
      };
      let facts = '';
      if (j.wantsAdmin) {
        facts = 'ลูกค้าตอบรับสนใจสมัครแล้วหลังได้รับรายละเอียดคอร์ส ให้ตอบรับสั้นๆ ว่าจะให้เจ้าหน้าที่ Dilion Education ติดต่อกลับผ่าน Line Official Account';
      } else if (!j.infoComplete) {
        const need = [];
        if (j.age === null) need.push('อายุ');
        if (j.hasBasic === null) need.push('มีพื้นฐานภาษาจีนหรือไม่');
        if (j.beenChina === null) need.push('เคยไปเรียนที่ประเทศจีนมาก่อนไหม');
        facts = 'ยังขาดข้อมูล: ' + need.join(', ') + '. ข้อมูลที่มีแล้ว (ห้ามถามซ้ำ): อายุ=' + (j.age??'-') + ' พื้นฐาน=' + (j.hasBasic===null?'-':(j.hasBasic?'มี':'ไม่มี')) + ' เคยไปจีน=' + (j.beenChina===null?'-':(j.beenChina?'เคย':'ไม่เคย')) + '. ให้ทักทายสั้นๆ (ถ้ายังไม่ทัก) แล้วถามเฉพาะข้อมูลที่ยังขาดเท่านั้น';
      } else if (!j.city) {
        facts = 'ข้อมูลครบแล้ว ให้เสนอเมืองให้เลือก: กว่างโจว, เซี่ยงไฮ้, เวยไห่, ฮาร์บิน แล้วถามว่าสนใจเมืองไหน';
      } else if (j.city === 'Guangzhou') {
        const img = j.hasBasic ? IMG.GuangzhouIntensive : IMG.Guangzhou;
        const courseName = j.hasBasic ? 'หลักสูตรเร่งรัด (Intensive)' : 'หลักสูตรปกติ (Standard)';
        facts = 'เมืองกว่างโจว มหาวิทยาลัย South China Normal University (SCNU) ไม่ต้องมีพื้นฐานภาษาจีนก็เรียนได้ทุกคอร์ส (ไม่ต้องใช้ HSK) สำหรับลูกค้านี้ (มีพื้นฐาน=' + (j.hasBasic?'มี':'ไม่มี') + ') แนะนำ ' + courseName + ' ให้แนบรูปโบรชัวร์ด้วย Markdown แบบนี้เป๊ะๆ: ![รายละเอียดคอร์ส](' + img + ') แล้วถามว่าสนใจนัดหมายไหมคะ';
      } else if (j.city === 'Shanghai') {
        const img = j.hasBasic ? IMG.ShanghaiIntensive : IMG.Shanghai;
        const courseName = j.hasBasic ? 'หลักสูตรเร่งรัด (ต้องมี HSK3 ขึ้นไป)' : 'หลักสูตรปกติ (ไม่ต้องมีพื้นฐาน)';
        facts = 'เมืองเซี่ยงไฮ้ มหาวิทยาลัย East China University of Science and Technology (ECUST) แนะนำ ' + courseName + ' ให้แนบรูปโบรชัวร์ด้วย Markdown แบบนี้เป๊ะๆ: ![รายละเอียดคอร์ส](' + img + ') แล้วถามว่าสนใจนัดหมายไหมคะ';
      } else if (j.city === 'Weihai') {
        facts = 'เมืองเวยไห่ มหาวิทยาลัย Shandong University Weihai Campus (SDUW) เมืองชายทะเล สงบ ปลอดภัย ไม่ต้องมีพื้นฐานภาษาจีนเลย ทุกคนสมัครได้ ให้แนบรูปโบรชัวร์ด้วย Markdown แบบนี้เป๊ะๆ: ![รายละเอียดคอร์ส](' + IMG.Weihai + ') แล้วถามว่าสนใจคอร์ส 1 เทอม หรือ 1 ปี';
      } else if (j.city === 'Harbin') {
        facts = 'เมืองฮาร์บิน มหาวิทยาลัย Harbin Engineering University (HEU) เมืองหนาวมีหิมะ เด่นด้านวิศวกรรม ไม่ต้องมีพื้นฐานภาษาจีนเลย (ไม่ต้องใช้ HSK) ให้แนบรูปโบรชัวร์ด้วย Markdown แบบนี้เป๊ะๆ: ![รายละเอียดคอร์ส](' + IMG.Harbin + ') แล้วถามว่าสนใจคอร์ส 1 เทอม หรือ 1 ปี';
      }
      return 'คุณคือเจ้าหน้าที่ Dilion Education ศูนย์แนะนำเรียนต่อประเทศจีน พูดสุภาพ ลงท้าย "ค่ะ" เสมอ ห้ามใช้ "ครับ" กระชับเป็นธรรมชาติ ห้ามมั่วราคา/เงื่อนไขที่ไม่ได้ให้มา ห้ามใส่ลิงก์รูปอื่นนอกจากที่ให้มาเป๊ะๆ\n\nข้อมูลที่ต้องใช้ตอบ: ' + facts;
    })() },
    ...$json.history
  ]
}) }}

